export default tool({
  description:
    "查看当前或历史的后台 Traе 任务的状态。后台任务通过 --background 参数启动，存储在 .claude-trae-plugin/ 目录。",
  args: {},
  async execute(args, context) {
    const { $ } = await import("bun")
    const result = await $`node ${DIST_INDEX} status`.cwd(PLUGIN_DIR)
    if (result.exitCode !== 0 && result.stderr) {
      process.stderr.write(result.stderr)
    }
    return { text: result.stdout }
  },
})

import { tool } from "@opencode-ai/plugin"
import path from "path"

const PLUGIN_DIR = path.dirname(path.dirname(import.meta.dir))
const DIST_INDEX = path.join(PLUGIN_DIR, "dist", "index.js")

export default tool({
  description:
    "获取特定后台 Trae 任务的输出日志。通过 `/trae:status` 或 status 工具获取任务 ID。",
  args: {
    task_id: tool.schema.string().describe("后台任务 ID（时间戳）"),
  },
  async execute(args, context) {
    const { $ } = await import("bun")
    const result = await $`node ${DIST_INDEX} result ${args.task_id}`
      .cwd(PLUGIN_DIR)
    if (result.exitCode !== 0 && result.stderr) {
      process.stderr.write(result.stderr)
    }
    return { text: result.stdout }

import { tool } from "@opencode-ai/plugin"
import path from "path"

const PLUGIN_DIR = path.dirname(path.dirname(import.meta.dir))
const DIST_INDEX = path.join(PLUGIN_DIR, "dist", "index.js")

export default tool({
  description:
    "强制取消特定的后台 Traе 任务。通过 `/trae:status` 或 status 工具获取任务 ID。",
  args: {
    task_id: tool.schema.string().describe("要取消的后台任务 ID（时间戳）"),
  },
  async execute(args, context) {
    const { $ } = await import("bun")
    const result = await $`node ${DIST_INDEX} cancel ${args.task_id}`
      .cwd(PLUGIN_DIR)
    if (result.exitCode !== 0 && result.stderr) {
      process.stderr.write(result.stderr)
    }
    return { text: result.stdout }

import { tool } from "@opencode-ai/plugin"
import path from "path"

const PLUGIN_DIR = path.dirname(path.dirname(import.meta.dir))
const DIST_INDEX = path.join(PLUGIN_DIR, "dist", "index.js")

export default tool({
  description:
    "当任务执行失败时，使用 Traе Agent 进行故障诊断。收集最近的错误日志、Git 状态等信息，并让 Traе 分析问题原因和恢复建议。",
  args: {
    context: tool.schema
      .string()
      .optional()
      .describe("提供额外的上下文信息帮助诊断"),
  },
  async execute(args, context) {
    const { $ } = await import("bun")
    const cliArgs: string[] = ["node", DIST_INDEX, "rescue"]
    if (args.context) cliArgs.push("--context", args.context)
    const result = await $`${cliArgs}`.cwd(PLUGIN_DIR)

