 import { detectBaseBranch, estimateReviewSize, formatEstimate } from '../utils/branch-detection';

 const executor = new TraeExecutor();

 function parseReviewArgs(args: string[], isAdversarial: boolean): TraeTaskConfig & { baseBranch: string } {
   const config: TraeTaskConfig & { baseBranch: string } = { prompt: '', baseBranch: 'main' };

   for (let i = 0; i < args.length; i++) {
     if (args[i] === '--base' && args[i + 1]) {
       config.baseBranch = args[i + 1];
       i++;
     } else if (args[i] === '--background') {
       config.background = true;
     } else if (args[i] === '--yolo' || args[i] === '-y') {
       config.yolo = true;
     } else if (args[i] === '--json') {
       config.jsonOutput = true;
     } else if (args[i] === '--session-id' && args[i + 1]) {
       config.sessionId = args[i + 1];
       i++;
     }
   }

   return config;
 }

 function buildReviewPrompt(isAdversarial: boolean, diff: string): string {
   const preamble = isAdversarial
     ? '作为一位极度严苛的对抗性代码审查员，请仔细检查以下变更。你需要专门挑刺、质疑假设、找出所有潜在的安全漏洞、性能瓶颈、逻辑错误或不符合最佳实践的地方。务必吹毛求疵，给出致命的反馈意见。'
     : '请对以下代码变更进行标准的专业代码审查。找出潜在的错误、性能问题、提出改进建议，并总结主要变动：';

   return `${preamble}\n\n代码变更如下:\n\`\`\`diff\n${diff}\n\`\`\``;
 }

 export async function review(args: string[], isAdversarial = false): Promise<void> {
   const parsed = parseReviewArgs(args, isAdversarial);

   const baseBranch = args.includes('--base')
     ? parsed.baseBranch
     : await detectBaseBranch();

   console.log('自动检测基准分支...');

   const estimate = await estimateReviewSize(baseBranch);
   console.log(formatEstimate(estimate));

   if (!parsed.background && estimate.recommendation.useBackground) {
     console.log('自动启用后台模式 (使用 --background 覆盖)');
     parsed.background = true;
   }

   console.log(`获取与 ${baseBranch} 的差异...`);
   const diff = await getGitDiff(baseBranch);

   if (!diff.trim()) {
     console.log('没有检测到任何代码变更。');
     return;
   }

   parsed.prompt = buildReviewPrompt(isAdversarial, diff);

   console.log('提交代码审查请求到 Trae Agent...');

   try {
     const result = await executor.execute(parsed);

     if (parsed.jsonOutput && result.jsonOutput) {
       console.log('\n结构化审查结果\n');
       console.log(JSON.stringify(result.jsonOutput, null, 2));
     } else if (parsed.background) {
       console.log('\n审查结果:\n');
       console.log(result.output);
     } else if (result.output) {
       console.log('\n审查结果\n');
       console.log(result.output);
     }

     if (result.sessionId) {
       console.log(`\n会话 ID: ${result.sessionId}`);
       console.log(`使用 run "继续审查" --resume ${result.sessionId} 恢复该会话`);
     }
   } catch (error: unknown) {
     console.error('审查执行出错:', error instanceof Error ? error.message : String(error));
     process.exit(1);
