   if (!serverManager.isRunning()) {
     console.log('正在启动 ACP Server...');
     try {
       await serverManager.start({ yolo: true });
     } catch (error: unknown) {
       console.error(`启动失败: ${error instanceof Error ? error.message : String(error)}`);
       return;
     }
   }

